appearance.styleContent:
/* Custom scrollbar */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: #0B0C0F; }
::-webkit-scrollbar-thumb { background: #E01A3E; border-radius: 3px; }

/* ─── BASE RESET — ensure rem = 16px so max-w-7xl = exactly 1280px ───────── */
html { font-size: 16px !important; scroll-behavior: smooth; }

body {
  background-color: #ffffff;
  font-family: "Nunito Sans", sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* ─── Explicit pixel container — bypasses any rem miscalculation ──────────── */
.max-w-7xl { max-width: 1280px !important; }
.max-w-6xl { max-width: 1152px !important; }
.max-w-5xl { max-width: 1024px !important; }
.max-w-4xl { max-width:  896px !important; }
.max-w-3xl { max-width:  768px !important; }
.max-w-2xl { max-width:  672px !important; }
.max-w-xl  { max-width:  576px !important; }
.max-w-lg  { max-width:  512px !important; }
.max-w-md  { max-width:  448px !important; }

/* ─── Font weight numeric aliases ─────────────────────────────────────────── */
.font-300 { font-weight: 300; }
.font-400 { font-weight: 400; }
.font-500 { font-weight: 500; }
.font-600 { font-weight: 600; }
.font-700 { font-weight: 700; }
.font-800 { font-weight: 800; }
.font-900 { font-weight: 900; }

/* ─── Typography: letter-spacing + line-height ────────────────────────────── */
.tracking-tighter { letter-spacing: -0.05em; }
.tracking-tight   { letter-spacing: -0.025em; }
.tracking-normal  { letter-spacing: 0em; }
.tracking-wide    { letter-spacing: 0.025em; }
.tracking-wider   { letter-spacing: 0.05em; }
.tracking-widest  { letter-spacing: 0.1em; }

.leading-none    { line-height: 1; }
.leading-tight   { line-height: 1.25; }
.leading-snug    { line-height: 1.375; }
.leading-normal  { line-height: 1.5; }
.leading-relaxed { line-height: 1.625; }
.leading-loose   { line-height: 2; }

/* ─── Animation keyframes ─────────────────────────────────────────────────── */
@keyframes slideUpFade {
  from { opacity: 0; transform: translateY(40px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes fadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}
.animate-slide-up { animation: slideUpFade 0.85s cubic-bezier(0.16, 1, 0.3, 1) both; }
.animate-fade-in  { animation: fadeIn 1s ease both; }

/* ─── Tailwind utility fallbacks ─────────────────────────────────────────── */
.blur-xl          { filter: blur(24px); }
.blur-2xl         { filter: blur(40px); }
.backdrop-blur-sm { -webkit-backdrop-filter: blur(4px); backdrop-filter: blur(4px); }
.antialiased      { -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }

.line-clamp-2 { overflow: hidden; display: -webkit-box; -webkit-box-orient: vertical; -webkit-line-clamp: 2; }
.line-clamp-3 { overflow: hidden; display: -webkit-box; -webkit-box-orient: vertical; -webkit-line-clamp: 3; }

/* Opacity modifier fallbacks */
.bg-primary\/10 { background-color: rgba(224,26,62,0.10); }
.bg-primary\/15 { background-color: rgba(224,26,62,0.15); }
.bg-primary\/20 { background-color: rgba(224,26,62,0.20); }
.text-primary\/90 { color: rgba(224,26,62,0.90); }
.shadow-primary\/30 { box-shadow: 0 10px 15px -3px rgba(224,26,62,0.30); }
.bg-bonds-dark\/80 { background-color: rgba(11,12,15,0.80); }
.bg-white\/5  { background-color: rgba(255,255,255,0.05); }
.bg-white\/10 { background-color: rgba(255,255,255,0.10); }
.bg-white\/15 { background-color: rgba(255,255,255,0.15); }
.bg-white\/20 { background-color: rgba(255,255,255,0.20); }
.text-white\/30 { color: rgba(255,255,255,0.30); }
.text-white\/40 { color: rgba(255,255,255,0.40); }
.text-white\/50 { color: rgba(255,255,255,0.50); }
.text-white\/60 { color: rgba(255,255,255,0.60); }
.text-white\/70 { color: rgba(255,255,255,0.70); }
.text-white\/75 { color: rgba(255,255,255,0.75); }
.text-white\/85 { color: rgba(255,255,255,0.85); }
.border-white\/10 { border-color: rgba(255,255,255,0.10); }
.border-white\/20 { border-color: rgba(255,255,255,0.20); }
.border-white\/30 { border-color: rgba(255,255,255,0.30); }
.border-white\/60 { border-color: rgba(255,255,255,0.60); }
.text-foreground\/50 { color: rgba(18,19,23,0.50); }
.text-foreground\/60 { color: rgba(18,19,23,0.60); }
.text-foreground\/70 { color: rgba(18,19,23,0.70); }
.text-foreground\/80 { color: rgba(18,19,23,0.80); }

/* ─── Color fallbacks ────────────────────────────────────────────────────── */
.bg-bonds-red      { background-color: #E01A3E; }
.text-bonds-red    { color: #E01A3E; }
.bg-bonds-red-deep { background-color: #B80A2A; }
.bg-bonds-gold     { background-color: #CCA166; }
.text-bonds-gold   { color: #CCA166; }
.bg-bonds-dark     { background-color: #0B0C0F; }
.text-bonds-dark   { color: #0B0C0F; }
.bg-bonds-surface  { background-color: #14161A; }
.bg-bonds-surface-2{ background-color: #1C1E23; }
.bg-primary        { background-color: #E01A3E; }
.text-primary      { color: #E01A3E; }
.border-primary    { border-color: #E01A3E; }
.hover\:border-primary:hover { border-color: #E01A3E; }
.hover\:text-primary:hover   { color: #E01A3E; }
.hover\:bg-bonds-red-deep:hover { background-color: #B80A2A; }
.bg-secondary      { background-color: #F3F4F6; }
.text-foreground   { color: #121317; }
.text-muted-foreground { color: #636D83; }
.border-border     { border-color: #DFE2E7; }

/* Navbar always on top */
.fixed.z-50 { z-index: 1000 !important; }
